import{_ as a,o as l,c as s,a9 as e}from"./chunks/framework.STMWz9Nm.js";const o=JSON.parse('{"title":"缓存设计与一致性","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/08-Redis学习/02-缓存设计与一致性.md","filePath":"语言/java/08-Redis学习/02-缓存设计与一致性.md","lastUpdated":1776150380000}'),h={name:"语言/java/08-Redis学习/02-缓存设计与一致性.md"};function t(r,i,n,k,d,p){return l(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="缓存设计与一致性" tabindex="-1">缓存设计与一致性 <a class="header-anchor" href="#缓存设计与一致性" aria-label="Permalink to “缓存设计与一致性”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>缓存设计关注的是如何用 Redis 为系统减压，并在性能和一致性之间取得合理平衡。<br> 它不是简单“把数据库结果放缓存里”这么直接。</p><p>一句话理解：</p><ul><li>缓存是数据库前的一层性能缓冲区</li><li>它不是数据真相来源，而是性能和稳定性的权衡层</li></ul><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>缓存方案设计不好，系统不仅不会更快，还可能变得更难维护。<br> 尤其在热点数据和高并发场景下，这些问题会非常突出：</p><ul><li>缓存穿透</li><li>缓存击穿</li><li>缓存雪崩</li><li>数据不一致</li></ul><h2 id="_3-先建立直觉-缓存命中率高-不代表缓存设计就好" tabindex="-1">3. 先建立直觉：缓存命中率高，不代表缓存设计就好 <a class="header-anchor" href="#_3-先建立直觉-缓存命中率高-不代表缓存设计就好" aria-label="Permalink to “3. 先建立直觉：缓存命中率高，不代表缓存设计就好”">​</a></h2><p>一个常见误区是：</p><ul><li>只盯命中率</li></ul><p>但缓存设计真正要同时考虑的是：</p><ul><li>命中率</li><li>一致性</li><li>热点风险</li><li>失效策略</li><li>故障时的兜底路径</li></ul><p>所以缓存不是“加上就好”，而是必须带着风险意识去设计。</p><h2 id="_4-核心内容" tabindex="-1">4. 核心内容 <a class="header-anchor" href="#_4-核心内容" aria-label="Permalink to “4. 核心内容”">​</a></h2><h3 id="_4-1-缓存旁路模式" tabindex="-1">4.1 缓存旁路模式 <a class="header-anchor" href="#_4-1-缓存旁路模式" aria-label="Permalink to “4.1 缓存旁路模式”">​</a></h3><p>最常见的 Cache Aside 思路是：</p><ol><li>先查缓存</li><li>没命中再查数据库</li><li>查到后回填缓存</li><li>更新时先改数据库，再删缓存</li></ol><p>它不是唯一方案，但通常是学习和工程落地的起点。</p><h3 id="_4-2-缓存更新策略" tabindex="-1">4.2 缓存更新策略 <a class="header-anchor" href="#_4-2-缓存更新策略" aria-label="Permalink to “4.2 缓存更新策略”">​</a></h3><p>常见设计包括：</p><ul><li>更新数据库后删除缓存</li><li>更新数据库后同步更新缓存</li><li>延迟双删</li><li>通过消息或 binlog 异步刷新缓存</li></ul><p>不同策略背后的本质问题都是：</p><ul><li>一致性代价怎么控制</li></ul><h3 id="_4-3-缓存穿透" tabindex="-1">4.3 缓存穿透 <a class="header-anchor" href="#_4-3-缓存穿透" aria-label="Permalink to “4.3 缓存穿透”">​</a></h3><p>缓存穿透指：</p><ul><li>请求的数据根本不存在</li><li>缓存没有</li><li>数据库也没有</li><li>所有请求都穿透到数据库</li></ul><p>常见应对：</p><ul><li>缓存空值</li><li>布隆过滤器</li><li>参数校验</li></ul><h3 id="_4-4-缓存击穿" tabindex="-1">4.4 缓存击穿 <a class="header-anchor" href="#_4-4-缓存击穿" aria-label="Permalink to “4.4 缓存击穿”">​</a></h3><p>缓存击穿通常指：</p><ul><li>某个热点 key 失效</li><li>大量请求同时打到数据库</li></ul><p>常见应对：</p><ul><li>互斥重建</li><li>热点 key 永不过期或逻辑过期</li><li>提前刷新</li></ul><h3 id="_4-5-缓存雪崩" tabindex="-1">4.5 缓存雪崩 <a class="header-anchor" href="#_4-5-缓存雪崩" aria-label="Permalink to “4.5 缓存雪崩”">​</a></h3><p>缓存雪崩通常指：</p><ul><li>大量 key 在同一时间失效</li><li>数据库被瞬时流量冲击</li></ul><p>常见应对：</p><ul><li>TTL 加随机值</li><li>多级缓存</li><li>限流降级</li><li>预热热点数据</li></ul><h3 id="_4-6-热点数据治理" tabindex="-1">4.6 热点数据治理 <a class="header-anchor" href="#_4-6-热点数据治理" aria-label="Permalink to “4.6 热点数据治理”">​</a></h3><p>热点问题本质上是：</p><ul><li>单个 key 的访问被无限放大</li></ul><p>常见处理：</p><ul><li>本地缓存 + Redis</li><li>热点 key 分片</li><li>单独保护热点链路</li><li>热点数据预热</li></ul><h2 id="_5-学习重点" tabindex="-1">5. 学习重点 <a class="header-anchor" href="#_5-学习重点" aria-label="Permalink to “5. 学习重点”">​</a></h2><p>这一章最重要的是掌握：</p><ul><li>缓存不是数据真相来源</li><li>穿透、击穿、雪崩是三种不同问题</li><li>一致性永远是缓存设计的重点问题</li><li>热点 key 需要专项治理</li></ul><h2 id="_6-常见问题" tabindex="-1">6. 常见问题 <a class="header-anchor" href="#_6-常见问题" aria-label="Permalink to “6. 常见问题”">​</a></h2><h3 id="_6-1-只考虑命中率-不考虑一致性" tabindex="-1">6.1 只考虑命中率，不考虑一致性 <a class="header-anchor" href="#_6-1-只考虑命中率-不考虑一致性" aria-label="Permalink to “6.1 只考虑命中率，不考虑一致性”">​</a></h3><p>这样系统可能会很快，但会越来越不可信。</p><h3 id="_6-2-所有-key-同时过期" tabindex="-1">6.2 所有 key 同时过期 <a class="header-anchor" href="#_6-2-所有-key-同时过期" aria-label="Permalink to “6.2 所有 key 同时过期”">​</a></h3><p>这是雪崩场景里最经典的错误之一。</p><h3 id="_6-3-热点-key-没有防护措施" tabindex="-1">6.3 热点 key 没有防护措施 <a class="header-anchor" href="#_6-3-热点-key-没有防护措施" aria-label="Permalink to “6.3 热点 key 没有防护措施”">​</a></h3><p>热点问题往往不是平均流量能看出来的，而是在瞬时高峰暴露。</p><h2 id="_7-动手验证" tabindex="-1">7. 动手验证 <a class="header-anchor" href="#_7-动手验证" aria-label="Permalink to “7. 动手验证”">​</a></h2><p>我已经验证过 Redis Docker 实验环境可用，你可以继续沿用：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-lab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FLUSHALL</span></span></code></pre></div><h3 id="_7-1-观察-ttl-与失效" tabindex="-1">7.1 观察 TTL 与失效 <a class="header-anchor" href="#_7-1-观察-ttl-与失效" aria-label="Permalink to “7.1 观察 TTL 与失效”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-lab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SETEX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:item:1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> value-1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-lab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TTL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:item:1</span></span></code></pre></div><p>这很适合体会：</p><ul><li>缓存并不是永久有效</li></ul><h3 id="_7-2-设计-随机-ttl-演练" tabindex="-1">7.2 设计“随机 TTL”演练 <a class="header-anchor" href="#_7-2-设计-随机-ttl-演练" aria-label="Permalink to “7.2 设计“随机 TTL”演练”">​</a></h3><p>把同类 key 的 TTL 不要都写成同一个值，而是设计成：</p><ul><li><code>600 ~ 660</code> 秒随机</li></ul><p>例如在代码层做：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ttl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> +</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> random.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nextInt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">60</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h3 id="_7-3-穿透与空值缓存演练" tabindex="-1">7.3 穿透与空值缓存演练 <a class="header-anchor" href="#_7-3-穿透与空值缓存演练" aria-label="Permalink to “7.3 穿透与空值缓存演练”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-lab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SETEX</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:user:404</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NULL</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-lab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:user:404</span></span></code></pre></div><p>你会看到：</p><ul><li>即使数据库里没有这个用户，也可以用短 TTL 的空值挡掉反复穿透</li></ul><h2 id="_8-练习建议" tabindex="-1">8. 练习建议 <a class="header-anchor" href="#_8-练习建议" aria-label="Permalink to “8. 练习建议”">​</a></h2><ul><li>设计一个商品详情缓存方案</li><li>模拟缓存击穿和雪崩场景</li><li>总结不同一致性策略的优缺点</li><li>为热点 key 设计专项保护方案</li></ul><h2 id="_9-自测问题" tabindex="-1">9. 自测问题 <a class="header-anchor" href="#_9-自测问题" aria-label="Permalink to “9. 自测问题”">​</a></h2><ul><li>缓存穿透、击穿、雪崩的区别是什么？</li><li>为什么缓存一致性很难做到绝对完美？</li><li>热点 key 应该怎样治理？</li><li>为什么缓存命中率高不等于设计就一定合理？</li></ul><h2 id="_10-自测核对要点" tabindex="-1">10. 自测核对要点 <a class="header-anchor" href="#_10-自测核对要点" aria-label="Permalink to “10. 自测核对要点”">​</a></h2><ul><li>穿透是查不存在数据，击穿是热点 key 失效，雪崩是大量 key 集中过期</li><li>一致性必须被设计出来，不能默认拥有</li><li>热点 key 会把单点压力放大成系统压力</li><li>缓存设计要同时考虑性能和稳定性</li></ul>`,76)])])}const F=a(h,[["render",t]]);export{o as __pageData,F as default};
